formValidator:
const errors = {};

    for (let i = 0; i < 25; i++) {
        const characteristicsKey = `specs__${i}__characteristics`;
        const tolPosKey = `specs__${i}__tol_pos`;
        const tolNegKey = `specs__${i}__tol_neg`;
        const isSingleVal = formData[`specs__${i}__is_single_val`];

        const characteristicsValue = formData[characteristicsKey];
        const tolPosValue = formData[tolPosKey];
        const tolNegValue = formData[tolNegKey];

        const hasAnyValue = !!(characteristicsValue || tolPosValue || tolPosValue === 0 || tolNegValue || tolNegValue === 0);

        if (hasAnyValue) {
            if (!characteristicsValue) {
                errors[characteristicsKey] = "Drawing Dimension is required";
            }
            if (!isSingleVal && !tolPosValue && tolPosValue !== 0) {
                errors[tolPosKey] = "+ve Tolerance is required";
            }
            if (!isSingleVal && !tolNegValue && tolNegValue !== 0) {
                errors[tolNegKey] = "-ve Tolerance is required";
            }
        }
    }

    return Object.keys(errors).length > 0 ? errors : undefined;
